UPDATE ATTENDANCE_OUT
SET
    ATT_OUT_START_DT = TO_DATE(SUBSTR(REPLACE(#{strOutStart}, 'T', ' '), 1, 16), 'YYYY-MM-DD HH24:MI'),
    ATT_OUT_END_DT = TO_DATE(SUBSTR(REPLACE(#{strOutEnd}, 'T', ' '), 1, 16), 'YYYY-MM-DD HH24:MI'),
    ATT_OUT_RSN = #{attOutRsn},
    ATT_OUT_TIME = #{attOutTime}
WHERE EMP_ID = #{empId}
AND ATT_OUT_ID = #{attOutId}
